DROP TABLE IF EXISTS `match_results`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `match_results` (
  `match_id` int NOT NULL AUTO_INCREMENT,
  `job_id` int DEFAULT NULL,
  `employee_id` int DEFAULT NULL,
  `match_score` decimal(5,2) DEFAULT NULL,
  `skill_match_score` decimal(5,2) DEFAULT NULL,
  `experience_match_score` decimal(5,2) DEFAULT NULL,
  `performance_match_score` decimal(5,2) DEFAULT NULL,
  `growth_potential_score` decimal(5,2) DEFAULT NULL,
  `notification_sent` tinyint(1) DEFAULT '0',
  `employee_viewed` tinyint(1) DEFAULT '0',
  `employee_applied` tinyint(1) DEFAULT '0',
  `match_date` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`match_id`),
  UNIQUE KEY `unique_job_employee` (`job_id`,`employee_id`),
  KEY `employee_id` (`employee_id`),
  CONSTRAINT `match_results_ibfk_1` FOREIGN KEY (`job_id`) REFERENCES `job_postings` (`job_id`),
  CONSTRAINT `match_results_ibfk_2` FOREIGN KEY (`employee_id`) REFERENCES `employees` (`employee_id`)
) ENGINE=InnoDB AUTO_INCREMENT=3038 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
